import React, { useState, useRef, useCallback } from 'react';

/**
 * SwipeableRow - A component for swipe-to-delete gestures.
 *
 * Usage:
 *   <SwipeableRow onDelete={() => removeItem(id)}>
 *     <MyListItem />
 *   </SwipeableRow>
 */
function SwipeableRow({ children, onDelete, deleteLabel = 'Delete', deleteColor = '#ef4444' }) {
  const rowRef = useRef(null);
  const innerRef = useRef(null);
  const deleteRef = useRef(null);

  const startX = useRef(0);
  const currentX = useRef(0);
  const offsetX = useRef(0);
  const isSwiping = useRef(false);
  const rafId = useRef(null);
  const rowWidth = useRef(0);

  const [deleting, setDeleting] = useState(false);

  const applyTransform = useCallback(() => {
    if (innerRef.current) {
      innerRef.current.style.transform = `translateX(${offsetX.current}px)`;
    }
    if (deleteRef.current) {
      const revealWidth = Math.min(Math.abs(offsetX.current), 120);
      deleteRef.current.style.width = `${revealWidth}px`;
      deleteRef.current.style.opacity = revealWidth > 20 ? '1' : '0';
    }
  }, []);

  const animateTo = useCallback((target, onComplete) => {
    const start = offsetX.current;
    const distance = target - start;
    const duration = 250;
    let startTime = null;

    const step = (timestamp) => {
      if (!startTime) startTime = timestamp;
      const elapsed = timestamp - startTime;
      const progress = Math.min(elapsed / duration, 1);
      const eased = 1 - Math.pow(1 - progress, 3);

      offsetX.current = start + distance * eased;
      applyTransform();

      if (progress < 1) {
        rafId.current = requestAnimationFrame(step);
      } else {
        offsetX.current = target;
        applyTransform();
        if (onComplete) onComplete();
      }
    };

    rafId.current = requestAnimationFrame(step);
  }, [applyTransform]);

  const confirmDelete = useCallback(() => {
    setDeleting(true);

    const row = rowRef.current;
    if (!row) {
      if (onDelete) onDelete();
      return;
    }

    const fullHeight = row.offsetHeight;
    const duration = 200;
    let startTime = null;

    const collapse = (timestamp) => {
      if (!startTime) startTime = timestamp;
      const elapsed = timestamp - startTime;
      const progress = Math.min(elapsed / duration, 1);
      const eased = 1 - Math.pow(1 - progress, 3);

      row.style.height = `${fullHeight * (1 - eased)}px`;
      row.style.opacity = `${1 - eased}`;
      row.style.overflow = 'hidden';

      if (progress < 1) {
        rafId.current = requestAnimationFrame(collapse);
      } else {
        row.style.height = '0px';
        row.style.opacity = '0';
        if (onDelete) onDelete();
      }
    };

    rafId.current = requestAnimationFrame(collapse);
  }, [onDelete]);

  const snapBack = useCallback(() => {
    animateTo(0);
  }, [animateTo]);

  const handleTouchStart = useCallback((e) => {
    if (deleting) return;
    if (rafId.current) cancelAnimationFrame(rafId.current);

    const touch = e.touches[0];
    startX.current = touch.clientX;
    currentX.current = touch.clientX;
    isSwiping.current = false;

    if (rowRef.current) {
      rowWidth.current = rowRef.current.offsetWidth;
    }
  }, [deleting]);

  const handleTouchMove = useCallback((e) => {
    if (deleting) return;

    const touch = e.touches[0];
    const deltaX = touch.clientX - startX.current;

    if (deltaX > 0) {
      offsetX.current = 0;
      applyTransform();
      return;
    }

    if (!isSwiping.current) {
      if (Math.abs(deltaX) > 10) {
        isSwiping.current = true;
      } else {
        return;
      }
    }

    currentX.current = touch.clientX;

    const raw = Math.abs(deltaX);
    const maxDrag = 120;
    if (raw > maxDrag) {
      const overflow = raw - maxDrag;
      const dampened = maxDrag + overflow * 0.3;
      offsetX.current = -dampened;
    } else {
      offsetX.current = deltaX;
    }

    if (rafId.current) cancelAnimationFrame(rafId.current);
    rafId.current = requestAnimationFrame(applyTransform);
  }, [deleting, applyTransform]);

  const handleTouchEnd = useCallback(() => {
    if (deleting) return;

    const swipeDistance = Math.abs(offsetX.current);
    const threshold = rowWidth.current * 0.4;

    if (swipeDistance >= threshold && rowWidth.current > 0) {
      animateTo(-rowWidth.current, confirmDelete);
    } else {
      snapBack();
    }
  }, [deleting, animateTo, confirmDelete, snapBack]);

  const handleDeleteClick = useCallback(() => {
    if (deleting) return;
    animateTo(-rowWidth.current || -300, confirmDelete);
  }, [deleting, animateTo, confirmDelete]);

  return (
    <div
      ref={rowRef}
      style={{
        position: 'relative',
        overflow: 'hidden',
        touchAction: 'pan-y',
      }}
    >
      <div
        ref={deleteRef}
        onClick={handleDeleteClick}
        style={{
          position: 'absolute',
          top: 0,
          right: 0,
          bottom: 0,
          width: 0,
          opacity: 0,
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          backgroundColor: deleteColor,
          color: '#ffffff',
          fontWeight: 600,
          fontSize: '14px',
          cursor: 'pointer',
          userSelect: 'none',
          whiteSpace: 'nowrap',
          zIndex: 1,
          transition: 'none',
        }}
        role="button"
        aria-label={deleteLabel}
      >
        {deleteLabel}
      </div>

      <div
        ref={innerRef}
        onTouchStart={handleTouchStart}
        onTouchMove={handleTouchMove}
        onTouchEnd={handleTouchEnd}
        style={{
          position: 'relative',
          zIndex: 2,
          backgroundColor: 'inherit',
          willChange: 'transform',
        }}
      >
        {children}
      </div>
    </div>
  );
}

/**
 * useSwipeToDelete - Hook that returns the SwipeableRow component.
 *
 * Usage:
 *   const { SwipeableRow } = useSwipeToDelete();
 */
export default function useSwipeToDelete() {
  return { SwipeableRow };
}
