/**
 * AURA Trading Desk — UpgradeNudge
 * Shows a contextual upgrade banner when user is near (≥80%) a tier limit.
 * Usage: <UpgradeNudge resource="alerts" />
 *        <UpgradeNudge resource="watchlists" />
 */
import usePlatformFeatures from '../hooks/usePlatformFeatures';

const C = {
  surface: '#0F1620',
  border: '#1F2A37',
  textPrimary: '#E5E7DB',
  textSecondary: '#90A3AF',
  green: '#22C55E',
  blue: '#60A5FA',
  amber: '#F59E0B',
  purple: '#A78BFA',
};
const mono = "'JetBrains Mono', monospace";
const body = "'Plus Jakarta Sans', sans-serif";

const RESOURCE_LABELS = {
  alerts: 'alerts',
  watchlists: 'watchlists',
  bots: 'live bots',
  strategies: 'strategies',
};

import { UPGRADE_PATH } from '../config/pricing';

const TIER_UPGRADE_MAP = Object.fromEntries(
  Object.entries(UPGRADE_PATH).map(([k, v]) => [k, v ? { next: v.nextLabel, price: v.nextPrice, contactSales: v.contactSales || false } : null])
);

export default function UpgradeNudge({ resource, threshold = 0.8 }) {
  const { tier, withinLimit, loading } = usePlatformFeatures();

  if (loading) return null;

  const { allowed, current, max } = withinLimit(resource);
  if (max <= 0 || max >= 999) return null; // unlimited

  const pct = current / max;
  if (pct < threshold) return null;

  const upgrade = TIER_UPGRADE_MAP[tier];
  if (!upgrade) return null; // already institutional

  const label = RESOURCE_LABELS[resource] || resource;
  const isOver = !allowed;
  const color = isOver ? C.amber : C.blue;

  return (
    <div style={{
      display: 'flex', alignItems: 'center', justifyContent: 'space-between',
      gap: 16, flexWrap: 'wrap',
      padding: '12px 18px', borderRadius: 10,
      background: `${color}0C`,
      border: `1px solid ${color}30`,
      marginBottom: 16,
    }}>
      <div style={{ display: 'flex', alignItems: 'center', gap: 12, minWidth: 0 }}>
        <span style={{
          fontSize: 18, lineHeight: 1,
          filter: isOver ? 'none' : 'grayscale(0.3)',
        }}>
          {isOver ? '\u26A0' : '\u2139'}
        </span>
        <div>
          <div style={{ fontSize: 13, fontWeight: 600, color: C.textPrimary, fontFamily: body }}>
            {isOver
              ? `You've reached your ${label} limit`
              : `You're using ${Math.round(pct * 100)}% of your ${label}`
            }
          </div>
          <div style={{ fontSize: 13, color: C.textSecondary, fontFamily: mono, marginTop: 4 }}>
            {current} / {max} {label} used
          </div>
        </div>
      </div>
      <a
        href={upgrade.contactSales ? '/contact-sales' : '/pricing-plans'}
        style={{
          padding: '8px 18px', borderRadius: 6,
          background: color, color: '#0B0F14',
          fontSize: 13, fontWeight: 700, fontFamily: body,
          textDecoration: 'none', whiteSpace: 'nowrap',
          transition: 'opacity 0.15s',
        }}
        onMouseEnter={(e) => { e.currentTarget.style.opacity = '0.85'; }}
        onMouseLeave={(e) => { e.currentTarget.style.opacity = '1'; }}
      >
        {upgrade.contactSales ? 'Contact Sales' : `Upgrade to ${upgrade.next}`}
      </a>
    </div>
  );
}
